#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[1000]; // N <= 1000
        for (int i = 0; i < N; ++i) {
            scanf("%d", &arr[i]);
        }
        int P;
        scanf("%d", &P);
        for (int i = P; i < N - 1; ++i) {
            arr[i] = arr[i + 1];
        }
        for (int i = 0; i < N - 1; ++i) {
            if (i) printf(" ");
            printf("%d", arr[i]);
        }
        printf("\n");
    }
    return 0;
}

